from typing import Dict, Any, List

TRUSTED_TOOLS = {
    'web_search': {'params': ['query'], 'max_results': 5},
    'calculator': {'params': ['expression']}
}

def validate_tool_call(call: Dict[str, Any]) -> bool:
    tool_name = call.get('name')
    if tool_name not in TRUSTED_TOOLS:
        return False

    schema = TRUSTED_TOOLS[tool_name]
    args = call.get('args', {})

    # Validate required params
    for param in schema['params']:
        if param not in args:
            return False

    # Block suspicious args
    suspicious = ['http', 'curl', 'exec', 'system']
    arg_str = str(args).lower()
    return not any(s in arg_str for s in suspicious)

