from copy import deepcopy

class SecureSession:
    def __init__(self):
        self._immutable_context = {}
        self._history = []

    def update_context(self, key: str, value: any):
        # Validate update
        if self._is_suspicious_update(key, value):
            raise ValueError(f'Suspicious context update: {key}')

        self._history.append(deepcopy(self._immutable_context))
        self._immutable_context[key] = value

    @property
    def context(self):
        return deepcopy(self._immutable_context)  # Read-only

    def _is_suspicious_update(self, key: str, value: any) -> bool:
        suspicious = ['system_prompt', 'instructions', 'tools']
        return any(s in key.lower() for s in suspicious) and len(str(value)) > 1000

